import React, { useState } from 'react';
import Barcode from 'react-barcode';
import { BiPrinter } from 'react-icons/bi';
import { useParams } from 'react-router-dom';
import s from './code-print.module.scss';   // 👈 импорт модуля

const CodePrint = () => {
  const { code, name, price } = useParams();
  const [qty, setQty] = useState(1);

  const labels = Array.from({ length: qty });

  return (
    <div className={s.wrapper}>
      {labels.map((_, i) => (
        <div key={i} className={s.label}>
          <h3>{name}</h3>
          <p>Стоимость: {price} сом</p>

          {/* штрих-код как canvas, чтобы XPrinter печатал без искажений */}
          <Barcode
            value={code}
            renderer="canvas"
            width={1.2}
            height={40}
            fontSize={14}
            margin={0}
            className={s.barcode}
          />
        </div>
      ))}

      <div className={s.controls}>
        <input
          type="number"
          min="1"
          value={qty}
          onChange={e => setQty(Math.max(+e.target.value, 1))}
        />
        <button onClick={() => window.print()}>
          Распечатать&nbsp;чек&nbsp;<BiPrinter />
        </button>
      </div>
    </div>
  );
};

export default CodePrint;
